const isRegexLikeMatch=/[*+\\(|{^$]/,isRegexLike=t=>isRegexLikeMatch.test(t);export const toRegexOrString=t=>"string"==typeof t&&isRegexLike(t)?new RegExp(t):t;export const findMatch=(t,e)=>t.find(t=>"string"==typeof t?t===e:t.test(e));const idCharMatch=/[a-zA-Z0-9$_]/;export const isIdChar=t=>idCharMatch.test(t);